// src/data/resourcesData.js
// Chess resources shown in the table on the Contact page.

const resourcesData = [
  {
    id: 1,
    name: 'Chess.com',
    url: 'https://chess.com',
    description: 'The largest chess platform in the world. Play live games, solve puzzles, watch lessons, and track your rating — all in one place.',
  },
  {
    id: 2,
    name: 'Lichess.org',
    url: 'https://lichess.org',
    description: 'A free, open-source chess platform with no ads and no paywalls. Millions of games every day, powerful analysis tools, and a strong community.',
  },
  {
    id: 3,
    name: 'FIDE',
    url: 'https://fide.com',
    description: 'The official International Chess Federation. Governs international competition, maintains world rankings, and organizes the World Chess Championship.',
  },
  {
    id: 4,
    name: 'Unsplash.com',
    url: 'https://unsplash.com',
    description: 'Source of the high-resolution photos used on this site. Over 6 million free images contributed by photographers worldwide.',
  },
];

export default resourcesData;
